1	package opencode
2	
3	import (
4		"context"
5		"encoding/json"
6		"errors"
7		"fmt"
8		"io"
9		"os"
10		osexec "os/exec"
11		"strings"
12		"sync/atomic"
13		"syscall"
14		"time"
15	
16		"github.com/easel/fizeau/internal/harnesses"
17	)
18	
19	const defaultEventBuffer = 64
20	
21	// Runner is the subprocess-backed opencode harness. It launches opencode in
22	// run --format json mode, parses the JSON output into harness Events, and
23	// emits a final Event when the subprocess exits.
24	//
25	// opencode run auto-approves all tool permissions; no extra flags are needed
26	// for any permission level.
27	type Runner struct {
28		// Binary is the absolute path to the opencode executable. When empty the
29		// runner resolves "opencode" via PATH at Execute time.
30		Binary string
31	
32		// BaseArgs is prepended to the per-request argument list.
33		// opencode default: ["run", "--format", "json"]
34		BaseArgs []string
35	
36		// PromptMode controls how the prompt is delivered:
37		//   "arg" (default) — prompt is appended as the final positional argument
38		//   "stdin"         — prompt is piped on stdin
39		PromptMode string
40	
41		// EventBuffer overrides the per-Execute channel buffer size.
42		EventBuffer int
43	}
44	
45	// Info returns identity + capability metadata for this harness.
46	func (r *Runner) Info() harnesses.HarnessInfo {
47		info := harnesses.HarnessInfo{
48			Name:                 "opencode",
49			Type:                 "subprocess",
50			IsLocal:              false,
51			IsSubscription:       false,
52			ExactPinSupport:      true,
53			DefaultModel:         "opencode/gpt-5.4",
54			SupportedPermissions: []string{"safe", "supervised", "unrestricted"},
55			SupportedReasoning:   []string{"minimal", "low", "medium", "high", "max"},
56			CostClass:            "medium",
57		}
58		path := r.Binary
59		if path == "" {
60			if resolved, err := osexec.LookPath("opencode"); err == nil {
61				path = resolved
62			}
63		}
64		if path != "" {
65			info.Path = path
66			info.Available = true
67		} else {
68			info.Error = "opencode binary not found in PATH"
69		}
70		return info
71	}
72	
73	// HealthCheck verifies the opencode binary is present.
74	func (r *Runner) HealthCheck(ctx context.Context) error {
75		if err := ctx.Err(); err != nil {
76			return err
77		}
78		path := r.Binary
79		if path == "" {
80			resolved, err := osexec.LookPath("opencode")
81			if err != nil {
82				return fmt.Errorf("opencode binary not found: %w", err)
83			}
84			path = resolved
85		}
86		st, err := os.Stat(path)
87		if err != nil {
88			return fmt.Errorf("stat opencode binary: %w", err)
89		}
90		if st.IsDir() {
91			return fmt.Errorf("opencode binary path is a directory: %s", path)
92		}
93		return nil
94	}
95	
96	// Execute runs one resolved request through the opencode CLI and emits
97	// JSON-derived events on the returned channel.
98	func (r *Runner) Execute(ctx context.Context, req harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
99		binary := r.Binary
100		if binary == "" {
101			resolved, err := osexec.LookPath("opencode")
102			if err != nil {
103				return nil, fmt.Errorf("opencode binary not found: %w", err)
104			}
105			binary = resolved
106		}
107	
108		bufSize := r.EventBuffer
109		if bufSize <= 0 {
110			bufSize = defaultEventBuffer
111		}
112	
113		out := make(chan harnesses.Event, bufSize)
114		go r.run(ctx, binary, req, out)
115		return out, nil
116	}
117	
118	func (r *Runner) run(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event) {
119		defer close(out)
120	
121		start := time.Now()
122		var seq int64
123	
124		agg, exitCode, stderr, runErr, status := r.runStreaming(ctx, binary, req, out, &seq)
125	
126		final := harnesses.FinalData{
127			Status:     status,
128			ExitCode:   exitCode,
129			DurationMS: time.Since(start).Milliseconds(),
130		}
131		if runErr != nil && status != "success" {
132			final.Error = runErr.Error()
133		} else if stderr != "" && status != "success" {
134			final.Error = trimErrorBlob(stderr)
135		}
136		if agg != nil {
137			final.FinalText = agg.FinalText
138			if agg.HasUsage {
139				final.Usage = &harnesses.FinalUsage{
140					InputTokens:  harnesses.IntPtr(agg.InputTokens),
141					OutputTokens: harnesses.IntPtr(agg.OutputTokens),
142					TotalTokens:  harnesses.IntPtr(agg.InputTokens + agg.OutputTokens),
143					Source:       harnesses.UsageSourceNativeStream,
144					Fresh:        harnesses.BoolPtr(true),
145				}
146			}
147			if agg.CostUSD > 0 {
148				final.CostUSD = agg.CostUSD
149			}
150		}
151	
152		finalRaw, err := json.Marshal(final)
153		if err != nil {
154			finalRaw = []byte(`{"status":"failed","error":"marshal final event"}`)
155		}
156		ev := harnesses.Event{
157			Type:     harnesses.EventTypeFinal,
158			Sequence: seq,
159			Time:     time.Now().UTC(),
160			Metadata: req.Metadata,
161			Data:     finalRaw,
162		}
163		select {
164		case out <- ev:
165		case <-time.After(time.Second):
166		}
167	}
168	
169	func (r *Runner) runStreaming(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event, seq *int64) (agg *streamAggregate, exitCode int, stderr string, runErr error, status string) {
170		base := r.BaseArgs
171		if base == nil {
172			base = []string{"run", "--format", "json"}
173		}
174		args := append([]string{}, base...)
175	
176		// opencode run auto-approves all tool permissions; no extra flags per level.
177	
178		// WorkDir flag: --dir <dir>
179		if req.WorkDir != "" {
180			args = append(args, "--dir", req.WorkDir)
181		}
182	
183		// Model flag: -m <model>
184		if req.Model != "" {
185			args = append(args, "-m", opencodeModelArg(req.Provider, req.Model))
186		}
187	
188		// Reasoning flag: --variant <reasoning>
189		if value := harnesses.AdapterReasoningValue(req); value != "" {
190			args = append(args, "--variant", value)
191		}
192	
193		promptMode := r.PromptMode
194		if promptMode == "" {
195			promptMode = "arg"
196		}
197		if promptMode == "arg" && req.Prompt != "" {
198			args = append(args, req.Prompt)
199		}
200	
201		runCtx, cancel := context.WithCancel(ctx)
202		defer cancel()
203	
204		cmd := harnesses.HarnessCommand(runCtx, binary, args...)
205		if req.WorkDir != "" {
206			cmd.Dir = req.WorkDir
207		}
208		if promptMode != "arg" {
209			cmd.Stdin = strings.NewReader(req.Prompt)
210		}
211		setProcessGroup(cmd)
212	
213		stdoutPipe, err := cmd.StdoutPipe()
214		if err != nil {
215			return nil, -1, "", err, "failed"
216		}
217		stderrPipe, err := cmd.StderrPipe()
218		if err != nil {
219			return nil, -1, "", err, "failed"
220		}
221	
222		if err := cmd.Start(); err != nil {
223			return nil, -1, "", err, "failed"
224		}
225	
226		progressLog, _ := harnesses.OpenProgressLog(req.SessionLogDir, req.SessionID, "opencode")
227		if progressLog != nil {
228			defer progressLog.Close()
229		}
230	
231		parserReader, parserWriter := io.Pipe()
232		parseDone := make(chan struct{})
233		var parseAgg *streamAggregate
234		var parseErr error
235		go func() {
236			defer close(parseDone)
237			mirrored, mirrorDone := harnesses.MirrorEvents(out, progressLog, ctx)
238			parseAgg, parseErr = parseOpencodeStream(runCtx, parserReader, mirrored, req.Metadata, seq)
239			close(mirrored)
240			<-mirrorDone
241		}()
242	
243		stdoutDone := make(chan struct{})
244		go func() {
245			defer close(stdoutDone)
246			_, _ = io.Copy(parserWriter, stdoutPipe)
247			_ = parserWriter.Close()
248		}()
249	
250		var stderrBuf strings.Builder
251		stderrDone := make(chan struct{})
252		go func() {
253			defer close(stderrDone)
254			_, _ = io.Copy(&stringBuilderWriter{&stderrBuf}, stderrPipe)
255		}()
256	
257		var timedOut atomic.Bool
258		if req.Timeout > 0 {
259			stop := make(chan struct{})
260			go func() {
261				select {
262				case <-stop:
263				case <-time.After(req.Timeout):
264					timedOut.Store(true)
265					cancel()
266					killProcessGroup(cmd)
267				}
268			}()
269			defer close(stop)
270		}
271	
272		cancelDone := make(chan struct{})
273		go func() {
274			defer close(cancelDone)
275			select {
276			case <-runCtx.Done():
277				killProcessGroup(cmd)
278			case <-stdoutDone:
279			}
280		}()
281	
282		<-stdoutDone
283		<-stderrDone
284		<-parseDone
285		runErr = cmd.Wait()
286		<-cancelDone
287		stderr = stderrBuf.String()
288	
289		switch {
290		case timedOut.Load():
291			return parseAgg, -1, stderr, context.DeadlineExceeded, "timed_out"
292		case ctx.Err() != nil && errors.Is(ctx.Err(), context.Canceled):
293			return parseAgg, -1, stderr, ctx.Err(), "cancelled"
294		case ctx.Err() != nil && errors.Is(ctx.Err(), context.DeadlineExceeded):
295			return parseAgg, -1, stderr, ctx.Err(), "timed_out"
296		case runErr != nil:
297			ec := -1
298			var exitErr *osexec.ExitError
299			if errors.As(runErr, &exitErr) {
300				ec = exitErr.ExitCode()
301			}
302			return parseAgg, ec, stderr, runErr, "failed"
303		}
304		if parseErr != nil && !errors.Is(parseErr, context.Canceled) {
305			return parseAgg, 0, stderr, parseErr, "failed"
306		}
307		return parseAgg, 0, stderr, nil, "success"
308	}
309	
310	func opencodeModelArg(provider, model string) string {
311		provider = strings.TrimSpace(provider)
312		model = strings.TrimSpace(model)
313		if provider == "" || model == "" || strings.Contains(model, "/") {
314			return model
315		}
316		return provider + "/" + model
317	}
318	
319	type stringBuilderWriter struct {
320		sb *strings.Builder
321	}
322	
323	func (w *stringBuilderWriter) Write(p []byte) (int, error) {
324		return w.sb.Write(p)
325	}
326	
327	func trimErrorBlob(s string) string {
328		const max = 2048
329		s = strings.TrimSpace(s)
330		if len(s) > max {
331			return s[:max] + "...(truncated)"
332		}
333		return s
334	}
335	
336	func setProcessGroup(cmd *osexec.Cmd) {
337		if cmd.SysProcAttr == nil {
338			cmd.SysProcAttr = &syscall.SysProcAttr{}
339		}
340		setProcessGroupAttr(cmd.SysProcAttr)
341	}
