1	package opencode
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7		"regexp"
8		"sort"
9		"strings"
10		"time"
11	
12		"github.com/easel/fizeau/internal/harnesses"
13	)
14	
15	const OpenCodeModelDiscoveryFreshnessWindow = 24 * time.Hour
16	
17	var opencodeModelLinePattern = regexp.MustCompile(`^[A-Za-z0-9_.-]+/[^\s]+$`)
18	
19	// OpenCodeModelCost captures the per-million-token prices printed by
20	// `opencode models --verbose`.
21	type OpenCodeModelCost struct {
22		InputUSDPerMTok      float64 `json:"input_usd_per_mtok"`
23		OutputUSDPerMTok     float64 `json:"output_usd_per_mtok"`
24		CacheReadUSDPerMTok  float64 `json:"cache_read_usd_per_mtok"`
25		CacheWriteUSDPerMTok float64 `json:"cache_write_usd_per_mtok"`
26	}
27	
28	// OpenCodeModelEvidence captures the stable model metadata exposed by
29	// `opencode models --verbose`. It intentionally does not include account or
30	// quota state because the current opencode CLI does not expose those as
31	// structured data.
32	type OpenCodeModelEvidence struct {
33		Model        string             `json:"model"`
34		ProviderID   string             `json:"provider_id,omitempty"`
35		ModelID      string             `json:"model_id,omitempty"`
36		Status       string             `json:"status,omitempty"`
37		Cost         *OpenCodeModelCost `json:"cost,omitempty"`
38		ContextLimit int                `json:"context_limit,omitempty"`
39		OutputLimit  int                `json:"output_limit,omitempty"`
40		Reasoning    bool               `json:"reasoning"`
41		ToolCall     bool               `json:"tool_call"`
42		Attachment   bool               `json:"attachment"`
43		Variants     []string           `json:"variants,omitempty"`
44	}
45	
46	func DefaultOpenCodeModelDiscovery() harnesses.ModelDiscoverySnapshot {
47		return harnesses.ModelDiscoverySnapshot{
48			CapturedAt:      time.Now().UTC(),
49			Models:          []string{"opencode/gpt-5.4", "opencode/claude-sonnet-4-6"},
50			ReasoningLevels: []string{"minimal", "low", "medium", "high", "max"},
51			Source:          "compatibility-table:opencode-cli",
52			FreshnessWindow: OpenCodeModelDiscoveryFreshnessWindow.String(),
53			Detail:          "opencode models lists provider/model IDs; opencode models --verbose includes per-model costs and variants; opencode run --help documents -m/--model and --variant",
54		}
55	}
56	
57	func ReadOpenCodeModelDiscovery(ctx context.Context, binary string, args ...string) (harnesses.ModelDiscoverySnapshot, error) {
58		if binary == "" {
59			binary = "opencode"
60		}
61		if len(args) == 0 {
62			args = []string{"models"}
63		}
64		cmd := harnesses.HarnessCommand(ctx, binary, args...)
65		out, err := cmd.CombinedOutput()
66		if err != nil {
67			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("opencode models: %w", err)
68		}
69		raw := string(out)
70		if len(parseOpenCodeModels(raw)) == 0 {
71			if evidence, err := ParseOpenCodeVerboseModelEvidence(raw); err != nil || len(evidence) == 0 {
72				return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("opencode models returned no provider/model IDs")
73			}
74		}
75		snapshot := opencodeDiscoveryFromText(raw, sourceForOpenCodeModelArgs(args))
76		models := snapshot.Models
77		if len(models) == 0 {
78			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("opencode models returned no provider/model IDs")
79		}
80		return snapshot, nil
81	}
82	
83	func ReadOpenCodeVerboseModelEvidence(ctx context.Context, binary string, args ...string) ([]OpenCodeModelEvidence, error) {
84		if binary == "" {
85			binary = "opencode"
86		}
87		if len(args) == 0 {
88			args = []string{"models", "--verbose"}
89		}
90		cmd := harnesses.HarnessCommand(ctx, binary, args...)
91		out, err := cmd.CombinedOutput()
92		if err != nil {
93			return nil, fmt.Errorf("opencode models --verbose: %w", err)
94		}
95		return ParseOpenCodeVerboseModelEvidence(string(out))
96	}
97	
98	func opencodeDiscoveryFromText(text, source string) harnesses.ModelDiscoverySnapshot {
99		snapshot := DefaultOpenCodeModelDiscovery()
100		if source != "" {
101			snapshot.Source = source
102		}
103		if evidence, err := ParseOpenCodeVerboseModelEvidence(text); err == nil && len(evidence) > 0 {
104			snapshot.Models = modelsFromOpenCodeEvidence(evidence)
105			if levels := reasoningLevelsFromOpenCodeEvidence(evidence); len(levels) > 0 {
106				snapshot.ReasoningLevels = levels
107			}
108			snapshot.Detail = fmt.Sprintf("opencode models --verbose returned %d model records; per-model costs are present for %d records; opencode run --help documents -m/--model and --variant", len(evidence), countOpenCodeCostEvidence(evidence))
109			return snapshot
110		}
111		if models := parseOpenCodeModels(text); len(models) > 0 {
112			snapshot.Models = models
113		}
114		return snapshot
115	}
116	
117	func parseOpenCodeModels(text string) []string {
118		text = strings.ReplaceAll(text, "\r\n", "\n")
119		out := make([]string, 0)
120		for _, line := range strings.Split(text, "\n") {
121			line = strings.TrimSpace(line)
122			if line == "" {
123				continue
124			}
125			fields := strings.Fields(line)
126			if len(fields) != 1 {
127				continue
128			}
129			model := fields[0]
130			if !opencodeModelLinePattern.MatchString(model) {
131				continue
132			}
133			out = appendUniqueString(out, model)
134		}
135		return out
136	}
137	
138	func appendUniqueString(values []string, value string) []string {
139		value = strings.TrimSpace(value)
140		if value == "" {
141			return values
142		}
143		for _, existing := range values {
144			if existing == value {
145				return values
146			}
147		}
148		return append(values, value)
149	}
150	
151	func sourceForOpenCodeModelArgs(args []string) string {
152		source := "cli:opencode models"
153		for _, arg := range args {
154			if arg == "--verbose" {
155				source = "cli:opencode models --verbose"
156				break
157			}
158		}
159		return source
160	}
161	
162	func ParseOpenCodeVerboseModelEvidence(text string) ([]OpenCodeModelEvidence, error) {
163		text = strings.ReplaceAll(text, "\r\n", "\n")
164		lines := strings.Split(text, "\n")
165		records := make([]OpenCodeModelEvidence, 0)
166		for i := 0; i < len(lines); i++ {
167			model := strings.TrimSpace(lines[i])
168			if !opencodeModelLinePattern.MatchString(model) {
169				continue
170			}
171			j := i + 1
172			for j < len(lines) && strings.TrimSpace(lines[j]) == "" {
173				j++
174			}
175			if j >= len(lines) || !strings.HasPrefix(strings.TrimSpace(lines[j]), "{") {
176				continue
177			}
178			block, next, err := collectOpenCodeJSONBlock(lines, j)
179			if err != nil {
180				return nil, fmt.Errorf("parse verbose model %q: %w", model, err)
181			}
182			record, err := decodeOpenCodeModelEvidence(model, block)
183			if err != nil {
184				return nil, fmt.Errorf("parse verbose model %q: %w", model, err)
185			}
186			records = append(records, record)
187			i = next
188		}
189		if len(records) == 0 {
190			return nil, fmt.Errorf("opencode verbose model output contained no JSON model records")
191		}
192		return records, nil
193	}
194	
195	func collectOpenCodeJSONBlock(lines []string, start int) (string, int, error) {
196		var block strings.Builder
197		depth := 0
198		started := false
199		inString := false
200		escaped := false
201		for i := start; i < len(lines); i++ {
202			if block.Len() > 0 {
203				block.WriteByte('\n')
204			}
205			line := lines[i]
206			block.WriteString(line)
207			for _, r := range line {
208				if escaped {
209					escaped = false
210					continue
211				}
212				if inString {
213					switch r {
214					case '\\':
215						escaped = true
216					case '"':
217						inString = false
218					}
219					continue
220				}
221				switch r {
222				case '"':
223					inString = true
224				case '{':
225					started = true
226					depth++
227				case '}':
228					depth--
229					if depth < 0 {
230						return "", i, fmt.Errorf("unexpected closing brace")
231					}
232				}
233			}
234			if started && depth == 0 {
235				return block.String(), i, nil
236			}
237		}
238		return "", len(lines) - 1, fmt.Errorf("unterminated JSON object")
239	}
240	
241	func decodeOpenCodeModelEvidence(model, raw string) (OpenCodeModelEvidence, error) {
242		var env struct {
243			ID         string          `json:"id"`
244			ProviderID string          `json:"providerID"`
245			Status     string          `json:"status"`
246			Cost       json.RawMessage `json:"cost"`
247			Limit      struct {
248				Context int `json:"context"`
249				Output  int `json:"output"`
250			} `json:"limit"`
251			Capabilities struct {
252				Reasoning  bool `json:"reasoning"`
253				ToolCall   bool `json:"toolcall"`
254				Attachment bool `json:"attachment"`
255			} `json:"capabilities"`
256			Variants map[string]json.RawMessage `json:"variants"`
257		}
258		if err := json.Unmarshal([]byte(raw), &env); err != nil {
259			return OpenCodeModelEvidence{}, err
260		}
261		evidence := OpenCodeModelEvidence{
262			Model:        model,
263			ProviderID:   env.ProviderID,
264			ModelID:      env.ID,
265			Status:       env.Status,
266			ContextLimit: env.Limit.Context,
267			OutputLimit:  env.Limit.Output,
268			Reasoning:    env.Capabilities.Reasoning,
269			ToolCall:     env.Capabilities.ToolCall,
270			Attachment:   env.Capabilities.Attachment,
271			Variants:     sortedOpenCodeVariantNames(env.Variants),
272		}
273		if len(env.Cost) > 0 && string(env.Cost) != "null" {
274			var cost struct {
275				Input  float64 `json:"input"`
276				Output float64 `json:"output"`
277				Cache  struct {
278					Read  float64 `json:"read"`
279					Write float64 `json:"write"`
280				} `json:"cache"`
281			}
282			if err := json.Unmarshal(env.Cost, &cost); err != nil {
283				return OpenCodeModelEvidence{}, err
284			}
285			evidence.Cost = &OpenCodeModelCost{
286				InputUSDPerMTok:      cost.Input,
287				OutputUSDPerMTok:     cost.Output,
288				CacheReadUSDPerMTok:  cost.Cache.Read,
289				CacheWriteUSDPerMTok: cost.Cache.Write,
290			}
291		}
292		return evidence, nil
293	}
294	
295	func sortedOpenCodeVariantNames(variants map[string]json.RawMessage) []string {
296		if len(variants) == 0 {
297			return nil
298		}
299		out := make([]string, 0, len(variants))
300		for variant := range variants {
301			out = append(out, variant)
302		}
303		sort.Slice(out, func(i, j int) bool {
304			left := openCodeVariantRank(out[i])
305			right := openCodeVariantRank(out[j])
306			if left == right {
307				return out[i] < out[j]
308			}
309			return left < right
310		})
311		return out
312	}
313	
314	func openCodeVariantRank(variant string) int {
315		switch variant {
316		case "none", "off":
317			return 0
318		case "minimal":
319			return 1
320		case "low":
321			return 2
322		case "medium":
323			return 3
324		case "high":
325			return 4
326		case "xhigh":
327			return 5
328		case "max":
329			return 6
330		default:
331			return 100
332		}
333	}
334	
335	func modelsFromOpenCodeEvidence(evidence []OpenCodeModelEvidence) []string {
336		out := make([]string, 0, len(evidence))
337		for _, item := range evidence {
338			out = appendUniqueString(out, item.Model)
339		}
340		return out
341	}
