343	func reasoningLevelsFromOpenCodeEvidence(evidence []OpenCodeModelEvidence) []string {
344		seen := map[string]bool{}
345		for _, item := range evidence {
346			for _, variant := range item.Variants {
347				seen[variant] = true
348			}
349		}
350		order := []string{"none", "minimal", "low", "medium", "high", "xhigh", "max"}
351		out := make([]string, 0, len(seen))
352		for _, variant := range order {
353			if seen[variant] {
354				out = append(out, variant)
355				delete(seen, variant)
356			}
357		}
358		extra := make([]string, 0, len(seen))
359		for variant := range seen {
360			extra = append(extra, variant)
361		}
362		sort.Strings(extra)
363		return append(out, extra...)
364	}
365	
366	func countOpenCodeCostEvidence(evidence []OpenCodeModelEvidence) int {
367		count := 0
368		for _, item := range evidence {
369			if item.Cost != nil {
370				count++
371			}
372		}
373		return count
374	}
