17	// DefaultPiModelDiscovery returns the compatibility-table fallback used when
18	// live pi CLI model discovery is unavailable.
19	func DefaultPiModelDiscovery() harnesses.ModelDiscoverySnapshot {
20		return harnesses.ModelDiscoverySnapshot{
21			CapturedAt:      time.Now().UTC(),
22			Models:          []string{"gemini-2.5-flash"},
23			ReasoningLevels: []string{"off", "minimal", "low", "medium", "high", "xhigh"},
24			Source:          "compatibility-table:pi-cli",
25			FreshnessWindow: PiModelDiscoveryFreshnessWindow.String(),
26			Detail:          "pi --help documents --model, --list-models, and --thinking levels; --list-models can refresh the concrete model table without invoking a model",
27		}
28	}
