30	// ReadPiModelDiscoveryFromHelp captures the stable pi --help surface. Help
31	// exposes the default model and thinking levels without requiring credentials.
32	func ReadPiModelDiscoveryFromHelp(ctx context.Context, binary string, args ...string) (harnesses.ModelDiscoverySnapshot, error) {
33		if binary == "" {
34			binary = "pi"
35		}
36		if len(args) == 0 {
37			args = []string{"--help"}
38		}
39		out, err := harnesses.HarnessCommand(ctx, binary, args...).CombinedOutput()
40		if err != nil {
41			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("pi help: %w", err)
42		}
43		snapshot := piDiscoveryFromHelp(string(out), "cli-help:pi")
44		if len(snapshot.Models) == 0 && len(snapshot.ReasoningLevels) == 0 {
45			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("pi help did not expose model or thinking metadata")
46		}
47		return snapshot, nil
48	}
