50	// ReadPiModelDiscoveryFromListModels captures the concrete model table from
51	// pi --list-models. The command prints catalog metadata and does not execute a
52	// prompt, but callers can fall back to ReadPiModelDiscoveryFromHelp if a local
53	// pi build lacks the command.
54	func ReadPiModelDiscoveryFromListModels(ctx context.Context, binary string, args ...string) (harnesses.ModelDiscoverySnapshot, error) {
55		if binary == "" {
56			binary = "pi"
57		}
58		if len(args) == 0 {
59			args = []string{"--list-models"}
60		}
61		out, err := harnesses.HarnessCommand(ctx, binary, args...).CombinedOutput()
62		if err != nil {
63			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("pi list models: %w", err)
64		}
65		models := parsePiListModels(string(out))
66		if len(models) == 0 {
67			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("pi list models did not expose any models")
68		}
69		snapshot := DefaultPiModelDiscovery()
70		snapshot.Models = models
71		snapshot.Source = "cli:list-models"
72		snapshot.Detail = "pi --list-models returned a concrete provider/model table; thinking levels come from the documented --thinking CLI surface"
73		return snapshot, nil
74	}
