82	// ReadPiModelDiscoveryFromListModelsForProviders parses `pi --list-models` and
83	// returns a snapshot whose Models list is restricted to the supplied provider
84	// names (case-insensitive). This is the surface used when a caller has
85	// configured local providers (e.g. lmstudio, omlx) and only wants Pi's
86	// concrete model table for those providers.
87	//
88	// If providers is empty the snapshot carries all discovered models.
89	func ReadPiModelDiscoveryFromListModelsForProviders(ctx context.Context, binary string, providers []string, args ...string) (harnesses.ModelDiscoverySnapshot, error) {
90		if binary == "" {
91			binary = "pi"
92		}
93		if len(args) == 0 {
94			args = []string{"--list-models"}
95		}
96		out, err := harnesses.HarnessCommand(ctx, binary, args...).CombinedOutput()
97		if err != nil {
98			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("pi list models: %w", err)
99		}
100		rows := parsePiListModelsWithProvider(string(out))
101		models := filterPiModelsByProviders(rows, providers)
102		if len(models) == 0 {
103			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("pi list models did not expose any models for providers %v", providers)
104		}
105		snapshot := DefaultPiModelDiscovery()
106		snapshot.Models = models
107		snapshot.Source = "cli:list-models:providers"
108		snapshot.Detail = "pi --list-models filtered to configured providers; thinking levels come from the documented --thinking CLI surface"
109		return snapshot, nil
110	}
