112	func piDiscoveryFromHelp(text, source string) harnesses.ModelDiscoverySnapshot {
113		snapshot := DefaultPiModelDiscovery()
114		if source != "" {
115			snapshot.Source = source
116		}
117		if model := parsePiDefaultModel(text); model != "" {
118			snapshot.Models = []string{model}
119		}
120		if levels := parsePiThinkingLevels(text); len(levels) > 0 {
121			snapshot.ReasoningLevels = levels
122		}
123		return snapshot
124	}
125	
126	func parsePiDefaultModel(text string) string {
127		m := piDefaultModelPattern.FindStringSubmatch(text)
128		if len(m) < 2 {
129			return ""
130		}
131		return strings.TrimSpace(m[1])
132	}
133	
134	func parsePiThinkingLevels(text string) []string {
135		for _, line := range strings.Split(strings.ReplaceAll(text, "\r\n", "\n"), "\n") {
136			if !strings.Contains(line, "--thinking") {
137				continue
138			}
139			_, after, ok := strings.Cut(line, "Set thinking level:")
140			if !ok {
141				continue
142			}
143			return uniquePiStrings(strings.Split(after, ","))
144		}
145		return nil
146	}
147	
148	func parsePiListModels(text string) []string {
149		rows := parsePiListModelsWithProvider(text)
150		models := make([]string, 0, len(rows))
151		for _, row := range rows {
152			models = append(models, row.Model)
153		}
154		return uniquePiStrings(models)
155	}
156	
157	func parsePiListModelsWithProvider(text string) []PiListModel {
158		var rows []PiListModel
159		var sawHeader bool
160		for _, line := range strings.Split(strings.ReplaceAll(text, "\r\n", "\n"), "\n") {
161			fields := strings.Fields(line)
162			if len(fields) >= 2 && strings.EqualFold(fields[0], "provider") && strings.EqualFold(fields[1], "model") {
163				sawHeader = true
164				continue
165			}
166			if !sawHeader || len(fields) < 6 {
167				continue
168			}
169			if fields[4] != "yes" && fields[4] != "no" {
170				continue
171			}
172			rows = append(rows, PiListModel{Provider: fields[0], Model: fields[1]})
173		}
174		return rows
175	}
176	
177	func filterPiModelsByProviders(rows []PiListModel, providers []string) []string {
178		var models []string
179		if len(providers) == 0 {
180			for _, row := range rows {
181				models = append(models, row.Model)
182			}
183			return uniquePiStrings(models)
184		}
185		allowed := make(map[string]bool, len(providers))
186		for _, p := range providers {
187			p = strings.TrimSpace(strings.ToLower(p))
188			if p != "" {
189				allowed[p] = true
190			}
191		}
192		for _, row := range rows {
193			if allowed[strings.ToLower(row.Provider)] {
194				models = append(models, row.Model)
195			}
196		}
197		return uniquePiStrings(models)
198	}
199	
200	func uniquePiStrings(values []string) []string {
201		out := make([]string, 0, len(values))
202		seen := map[string]bool{}
203		for _, value := range values {
204			value = strings.TrimSpace(value)
205			if value == "" || seen[value] {
206				continue
207			}
208			seen[value] = true
209			out = append(out, value)
210		}
211		return out
212	}
