257	// RunModelDiscoveryHarnessConformance asserts the ModelDiscoveryHarness
258	// contract.
259	//
260	//   - The base Harness contract via RunHarnessConformance.
261	//   - DefaultModelSnapshot returns a non-empty model list.
262	//   - For every alias in SupportedAliases(), ResolveModelAlias returns
263	//     a non-empty model and a nil error (positive path).
264	//   - ResolveModelAlias returns ErrAliasNotResolvable for an
265	//     out-of-set family (negative path).
266	//   - Empty SupportedAliases() (allowed for opencode/pi-style
267	//     harnesses) skips the positive-path assertion but still drives
268	//     the negative path.
269	func RunModelDiscoveryHarnessConformance(t *testing.T, h harnesses.ModelDiscoveryHarness) {
270		t.Helper()
271		if h == nil {
272			t.Fatal("RunModelDiscoveryHarnessConformance called with nil harness")
273		}
274	
275		RunHarnessConformance(t, h)
276	
277		t.Run("DefaultModelSnapshotNonEmpty", func(t *testing.T) {
278			snap := h.DefaultModelSnapshot()
279			if len(snap.Models) == 0 {
280				t.Errorf("DefaultModelSnapshot().Models is empty; want at least one seed model")
281			}
282		})
283	
284		snapshot := h.DefaultModelSnapshot()
285		aliases := h.SupportedAliases()
286	
287		t.Run("SupportedAliasesStable", func(t *testing.T) {
288			b := h.SupportedAliases()
289			if !stringSetEqual(aliases, b) {
290				t.Errorf("SupportedAliases not stable: first=%v second=%v", aliases, b)
291			}
292		})
293	
294		t.Run("ResolveModelAliasPositive", func(t *testing.T) {
295			if len(aliases) == 0 {
296				t.Skip("SupportedAliases is empty; positive path skipped per CONTRACT-004")
297			}
298			for _, alias := range aliases {
299				model, err := h.ResolveModelAlias(alias, snapshot)
300				if err != nil {
301					t.Errorf("ResolveModelAlias(%q) error = %v, want nil", alias, err)
302					continue
303				}
304				if model == "" {
305					t.Errorf("ResolveModelAlias(%q) returned empty model with nil error", alias)
306				}
307			}
308		})
309	
310		t.Run("ResolveModelAliasNegative", func(t *testing.T) {
311			const outOfSet = "__harnesstest_definitely_not_a_real_family__"
312			if containsString(aliases, outOfSet) {
313				t.Skipf("sentinel out-of-set family %q is in SupportedAliases(); skipping negative path", outOfSet)
314			}
315			model, err := h.ResolveModelAlias(outOfSet, snapshot)
316			if !errors.Is(err, harnesses.ErrAliasNotResolvable) {
317				t.Errorf("ResolveModelAlias(%q) error = %v, want ErrAliasNotResolvable", outOfSet, err)
318			}
319			if model != "" {
320				t.Errorf("ResolveModelAlias(%q) returned model %q with non-resolvable error; want empty", outOfSet, model)
321			}
322		})
323	}
