15	func TestRunnerInfoMatchesRegistryMetadata(t *testing.T) {
16		registry := harnesses.NewRegistry()
17		cases := []struct {
18			name string
19			info harnesses.HarnessInfo
20		}{
21			{name: "codex", info: (&codexharness.Runner{Binary: "/test/codex"}).Info()},
22			{name: "claude", info: (&claudeharness.Runner{Binary: "/test/claude"}).Info()},
23			{name: "gemini", info: (&geminiharness.Runner{Binary: "/test/gemini"}).Info()},
24			{name: "opencode", info: (&opencodeharness.Runner{Binary: "/test/opencode"}).Info()},
25			{name: "pi", info: (&piharness.Runner{Binary: "/test/pi"}).Info()},
26		}
27	
28		for _, tc := range cases {
29			t.Run(tc.name, func(t *testing.T) {
30				cfg, ok := registry.Get(tc.name)
31				if !ok {
32					t.Fatalf("registry missing %s", tc.name)
33				}
34				if tc.info.Name != cfg.Name {
35					t.Fatalf("Name: got %q, want %q", tc.info.Name, cfg.Name)
36				}
37				if tc.info.ExactPinSupport != cfg.ExactPinSupport {
38					t.Fatalf("ExactPinSupport: got %v, want %v", tc.info.ExactPinSupport, cfg.ExactPinSupport)
39				}
40				if tc.info.DefaultModel != cfg.DefaultModel {
41					t.Fatalf("DefaultModel: got %q, want %q", tc.info.DefaultModel, cfg.DefaultModel)
42				}
43				if tc.info.CostClass != cfg.CostClass {
44					t.Fatalf("CostClass: got %q, want %q", tc.info.CostClass, cfg.CostClass)
45				}
46				if tc.info.IsLocal != cfg.IsLocal {
47					t.Fatalf("IsLocal: got %v, want %v", tc.info.IsLocal, cfg.IsLocal)
48				}
49				if tc.info.IsSubscription != cfg.IsSubscription {
50					t.Fatalf("IsSubscription: got %v, want %v", tc.info.IsSubscription, cfg.IsSubscription)
51				}
52				if tc.info.AutoRoutingEligible != cfg.AutoRoutingEligible {
53					t.Fatalf("AutoRoutingEligible: got %v, want %v", tc.info.AutoRoutingEligible, cfg.AutoRoutingEligible)
54				}
55				assertStringSet(t, "SupportedPermissions", tc.info.SupportedPermissions, registryPermissions(cfg))
56				assertStringSet(t, "SupportedReasoning", tc.info.SupportedReasoning, cfg.ReasoningLevels)
57			})
58		}
59	}
60	
61	func registryPermissions(cfg harnesses.HarnessConfig) []string {
62		if len(cfg.PermissionArgs) == 0 {
63			return nil
64		}
65		perms := make([]string, 0, len(cfg.PermissionArgs))
66		for perm := range cfg.PermissionArgs {
67			perms = append(perms, perm)
68		}
69		sort.Strings(perms)
70		return perms
71	}
72	
73	func assertStringSet(t *testing.T, label string, got, want []string) {
74		t.Helper()
75		got = append([]string(nil), got...)
76		want = append([]string(nil), want...)
77		sort.Strings(got)
78		sort.Strings(want)
79		if len(got) != len(want) {
80			t.Fatalf("%s: got %v, want %v", label, got, want)
81		}
82		for i := range got {
83			if got[i] != want[i] {
84				t.Fatalf("%s: got %v, want %v", label, got, want)
85			}
86		}
87	}
