	allowed := make(map[string]bool, len(providers))
	for _, p := range providers {
		p = strings.TrimSpace(strings.ToLower(p))
		if p != "" {
			allowed[p] = true
		}
	}
	for _, row := range rows {
		if allowed[strings.ToLower(row.Provider)] {
